import React, { useState } from 'react';
import { Target, AlertCircle, CheckCircle } from 'lucide-react';

const BudgetSettings = () => {
  const [budgets, setBudgets] = useState({
    monthly: 3000,
    food: 500,
    transport: 300,
    entertainment: 200,
    shopping: 400
  });

  const [actualSpending, setActualSpending] = useState({
    food: 320,
    transport: 280,
    entertainment: 150,
    shopping: 350
  });

  const handleBudgetChange = (category, value) => {
    setBudgets(prev => ({
      ...prev,
      [category]: parseFloat(value) || 0
    }));
  };

  const getBudgetStatus = (category) => {
    const spent = actualSpending[category] || 0;
    const budget = budgets[category] || 0;
    const percentage = budget > 0 ? (spent / budget) * 100 : 0;
    
    if (percentage >= 90) return 'over';
    if (percentage >= 75) return 'warning';
    return 'good';
  };

  return (
    <div className="budget-settings">
      <div className="page-header">
        <h1><Target size={24} /> Budget Settings</h1>
      </div>
      
      <div className="budget-table-compact">
        {/* Food Row */}
        <div className="budget-table-row">
          <div className="budget-table-cell category-cell">
            <strong>Food</strong>
          </div>
          <div className="budget-table-cell amount-cell">
            <strong>${budgets.food}</strong>
          </div>
        </div>
        <div className="budget-table-row">
          <div className="budget-table-cell spent-cell">
            Spent: ${actualSpending.food}
          </div>
          <div className="budget-table-cell percentage-cell">
            {budgets.food > 0 ? ((actualSpending.food / budgets.food) * 100).toFixed(1) : 0}%
          </div>
        </div>

        {/* Transport Row */}
        <div className="budget-table-row">
          <div className="budget-table-cell category-cell">
            <strong>Transport</strong>
          </div>
          <div className="budget-table-cell amount-cell">
            <strong>${budgets.transport}</strong>
          </div>
        </div>
        <div className="budget-table-row">
          <div className="budget-table-cell spent-cell">
            Spent: ${actualSpending.transport}
          </div>
          <div className="budget-table-cell percentage-cell">
            {budgets.transport > 0 ? ((actualSpending.transport / budgets.transport) * 100).toFixed(1) : 0}%
          </div>
        </div>

        {/* Entertainment Row */}
        <div className="budget-table-row">
          <div className="budget-table-cell category-cell">
            <strong>Entertainment</strong>
          </div>
          <div className="budget-table-cell amount-cell">
            <strong>${budgets.entertainment}</strong>
          </div>
        </div>
        <div className="budget-table-row">
          <div className="budget-table-cell spent-cell">
            Spent: ${actualSpending.entertainment}
          </div>
          <div className="budget-table-cell percentage-cell">
            {budgets.entertainment > 0 ? ((actualSpending.entertainment / budgets.entertainment) * 100).toFixed(1) : 0}%
          </div>
        </div>

        {/* Shopping Row */}
        <div className="budget-table-row">
          <div className="budget-table-cell category-cell">
            <strong>Shopping</strong>
          </div>
          <div className="budget-table-cell amount-cell">
            <strong>${budgets.shopping}</strong>
          </div>
        </div>
        <div className="budget-table-row">
          <div className="budget-table-cell spent-cell">
            Spent: ${actualSpending.shopping}
          </div>
          <div className="budget-table-cell percentage-cell">
            {budgets.shopping > 0 ? ((actualSpending.shopping / budgets.shopping) * 100).toFixed(1) : 0}%
          </div>
        </div>
      </div>
    </div>
  );
};

export default BudgetSettings;
